/*
 * Rebound, tool demo overrides.
 * Loaded after the generated demos to replace any that read poorly. The physics
 * card demos (spring / recoil / bounce) are generated by SAMPLING the real
 * easing engine, mapped onto the SAME sample shape, axis, and direction the
 * in-tool preview uses, so the showcase and the preview read as the same motion.
 * Every loop is buttery: the sample plays, holds, then fades out across the seam
 * while the reset happens unseen, and fades back in (matching the preview loop).
 * Smooth morphs a jagged polyline into a flowing one (same point count, so the
 * path never snaps).
 */
;(function (R) {
  'use strict';
  if (!R.registerToolDemo) return;

  function r(v) { return Math.round(v * 100) / 100; }

  var DUR = '3.4s';

  // Build a looping transform value/keyTime pair by sampling fn(t) over the play
  // band, holding briefly at the settled value, then gliding smoothly back to the
  // start (the same gentle return the preview uses, so there is no fade or jump).
  // `map` turns a sampled value into the attribute string; `resetVal` is the
  // start. The final segment (hold -> start) is the return.
  function sampleSMIL(fn, n, map, resetVal) {
    var playEnd = 0.55;
    var values = [];
    var keyTimes = [];
    for (var i = 0; i <= n; i++) {
      var t = i / n;
      values.push(map(fn(t)));
      keyTimes.push(r(t * playEnd));
    }
    values.push(map(fn(1))); keyTimes.push(0.68); // brief hold at the end
    values.push(resetVal); keyTimes.push(1);      // glide back to the start
    return { values: values.join(';'), keyTimes: keyTimes.join(';') };
  }

  function moving(s) {
    return '<animateTransform attributeName="transform" type="translate" values="' + s.values + '" ' +
      'keyTimes="' + s.keyTimes + '" dur="' + DUR + '" calcMode="linear" repeatCount="indefinite"/>';
  }

  var sampler = R.easing && R.easing.sampler;

  // ---- Spring / Recoil / Bounce: same motion as each tool's preview --------
  if (sampler) {
    // Spring: a rounded square slides to its mark and overshoots past it, then
    // settles (horizontal, like the Spring position preview).
    var springFn = sampler.toFunction({ type: 'spring', response: 0.5, bounce: 0.35 });
    var sp = sampleSMIL(springFn, 32, function (v) { return r(v * 64) + ',0'; }, '0,0');
    R.registerToolDemo('spring',
      '<strong>Spring.</strong> The engine’s real physical overshoot, settling onto the target.',
      '<svg viewBox="0 0 120 72" preserveAspectRatio="xMidYMid meet">' +
        '<line x1="89" y1="16" x2="89" y2="56" stroke="currentColor" stroke-width="1" stroke-dasharray="2 3" opacity="0.3"/>' +
        '<rect x="14" y="25" width="22" height="22" rx="6" style="fill:var(--rb-accent)">' + moving(sp) + '</rect>' +
        '</svg>');

    // Recoil: a quick move to the mark, then a decaying wobble around it (the
    // velocity-driven oscillation the rig produces), distinct from Spring's
    // single overshoot. Same makeRecoil shape the Recoil preview plays.
    var rc = sampleSMIL(makeRecoil(0.4, 2.5, 2.4), 52, function (v) { return r(v * 64) + ',0'; }, '0,0');
    R.registerToolDemo('recoil',
      '<strong>Recoil.</strong> Velocity-driven wobble around the mark, settling.',
      '<svg viewBox="0 0 120 72" preserveAspectRatio="xMidYMid meet">' +
        '<line x1="89" y1="16" x2="89" y2="56" stroke="currentColor" stroke-width="1" stroke-dasharray="2 3" opacity="0.3"/>' +
        '<rect x="14" y="25" width="22" height="22" rx="6" style="fill:var(--rb-accent)">' + moving(rc) + '</rect>' +
        '</svg>');

    // Bounce: a rounded square falls onto the floor and rebounds, each bounce
    // smaller (vertical, like the Bounce position preview). Same parametric
    // bounce the preview plays.
    var bounceFn = makeBounce(0.7, 4);
    var bc = sampleSMIL(bounceFn, 40, function (v) { return '0,' + r(v * 32); }, '0,0');
    R.registerToolDemo('bounce',
      '<strong>Bounce.</strong> A gravitational rebound off the target, each bounce smaller.',
      '<svg viewBox="0 0 120 72" preserveAspectRatio="xMidYMid meet">' +
        '<line x1="40" y1="58" x2="80" y2="58" stroke="currentColor" stroke-width="1.5" opacity="0.3"/>' +
        '<rect x="50" y="6" width="20" height="20" rx="6" style="fill:var(--rb-accent)">' + moving(bc) + '</rect>' +
        '</svg>');
  }

  // The recoil shape from features/recoil.js, so the card matches the tool: a
  // smooth move to the mark, then a decaying sine wobble around it.
  function makeRecoil(amp, freq, dec) {
    return function (t) {
      if (t <= 0) return 0;
      if (t >= 1) return 1;
      var riseT = 0.18;
      if (t < riseT) { var u = t / riseT; return u * u * (3 - 2 * u); }
      var sn = (t - riseT) / (1 - riseT);
      return 1 + amp * Math.sin(freq * sn * 2 * Math.PI) / Math.exp(dec * sn);
    };
  }

  // The exact bounce model from features/bounce.js, so the card matches the tool.
  function makeBounce(elas, bounces) {
    var e = Math.max(0.15, Math.min(0.85, elas));
    var n = Math.max(1, Math.min(8, Math.round(bounces)));
    var widths = [1.0];
    var drops = [];
    var base = 0.2 + 0.12 * e;
    for (var k = 1; k <= n; k++) { var d = base * Math.pow(e, k - 1); drops.push(d); widths.push(2.4 * Math.sqrt(d)); }
    var total = 0, i;
    for (i = 0; i < widths.length; i++) total += widths[i];
    var nw = widths.map(function (x) { return x / total; });
    var starts = [0];
    for (i = 1; i < nw.length; i++) starts.push(starts[i - 1] + nw[i - 1]);
    return function (t) {
      if (t <= 0) return 0;
      if (t >= 1) return 1;
      if (t < starts[1]) { var u = t / nw[0]; return u * u * (3 - 2 * u); }
      for (var s = 1; s <= n; s++) {
        var s0 = starts[s];
        var s1 = (s < n) ? starts[s + 1] : 1;
        if (t < s1 || s === n) {
          var u2 = (t - s0) / (s1 - s0);
          return 1 - drops[s - 1] * 4 * u2 * (1 - u2);
        }
      }
      return 1;
    };
  }

  // ---- Smooth: jagged polyline relaxes into a flowing one ------------------
  // Both paths sample the SAME x positions, so only the y values morph and the
  // line never snaps. The morph is symmetric (same ease in and out) and the dots
  // move on the same ease as the line, so they travel together.
  var KX = [14, 32, 52, 71, 90, 106];
  var JY = [50, 18, 54, 20, 48, 28];
  var SY = [41, 34, 38, 33, 36, 36];
  var SMOOTH_KT = '0;0.42;0.8;1';
  var SMOOTH_S = '0.4 0 0.2 1;0 0 1 1;0.4 0 0.2 1';

  function catmull(Y, seg, t) {
    var p0 = Y[Math.max(0, seg - 1)];
    var p1 = Y[seg];
    var p2 = Y[seg + 1];
    var p3 = Y[Math.min(Y.length - 1, seg + 2)];
    var t2 = t * t;
    var t3 = t2 * t;
    return 0.5 * ((2 * p1) + (-p0 + p2) * t + (2 * p0 - 5 * p1 + 4 * p2 - p3) * t2 + (-p0 + 3 * p1 - 3 * p2 + p3) * t3);
  }

  (function () {
    var N = 30;
    var segs = KX.length - 1;
    var jd = '';
    var sd = '';
    for (var i = 0; i <= N; i++) {
      var u = (i / N) * segs;
      var seg = Math.min(segs - 1, Math.floor(u));
      var t = u - seg;
      var x = KX[seg] + (KX[seg + 1] - KX[seg]) * t;
      var jy = JY[seg] + (JY[seg + 1] - JY[seg]) * t;
      var sy = catmull(SY, seg, t);
      jd += (i ? 'L' : 'M') + r(x) + ' ' + r(jy) + ' ';
      sd += (i ? 'L' : 'M') + r(x) + ' ' + r(sy) + ' ';
    }
    jd = jd.replace(/\s+$/, '');
    sd = sd.replace(/\s+$/, '');

    var dots = '';
    for (var k = 0; k < KX.length; k++) {
      dots += '<circle cx="' + KX[k] + '" cy="' + JY[k] + '" r="2.7">' +
        '<animate attributeName="cy" values="' + JY[k] + ';' + SY[k] + ';' + SY[k] + ';' + JY[k] + '" ' +
        'keyTimes="' + SMOOTH_KT + '" dur="4s" calcMode="spline" keySplines="' + SMOOTH_S + '" repeatCount="indefinite"/></circle>';
    }

    R.registerToolDemo('smooth',
      '<strong>Smooth keyframes.</strong> A jagged, angular path relaxes into a flowing curve, then repeats.',
      '<svg viewBox="0 0 120 72" preserveAspectRatio="xMidYMid meet">' +
        '<path fill="none" style="stroke:var(--rb-accent)" stroke-width="2" stroke-linejoin="round" stroke-linecap="round" d="' + jd + '">' +
        '<animate attributeName="d" values="' + jd + ';' + sd + ';' + sd + ';' + jd + '" ' +
        'keyTimes="' + SMOOTH_KT + '" dur="4s" calcMode="spline" keySplines="' + SMOOTH_S + '" repeatCount="indefinite"/></path>' +
        '<g style="fill:var(--rb-accent)">' + dots + '</g>' +
        '</svg>');
  })();
})(window.Rebound = window.Rebound || {});
